// Guard - Stop workflow if the ticket belongs to a filtered team
const body = $json.body || {};
const teamName = String(body.team ?? body.ticket?.team ?? '').toLowerCase();
const teamId = Number(body.team_id ?? body.ticket?.team_id ?? NaN);
const isFiltered = teamName === 'sales' || teamId === 6; // <- change these
if (isFiltered) return []; // stop
return $input.all();

const ticket = $input.item.json.body?.ticket;
if (!ticket) throw new Error('No ticket object found in webhook payload.');
const summaryCard = `🆕 New ticket created

🧾 Ticket ID: ${ticket.id}
🧑‍💻 Summary: ${ticket.summary}
📝 Description: ${ticket.details || 'No details provided.'}
`;
return [{ json: { ticket_id: ticket.id, summary_card: summaryCard, details: ticket.details || '', subject: ticket.summary } }];

const { subject, details, ticket_id } = $input.item.json;
const prompt = `You are a senior MSP engineer. Analyze the support ticket and return **strict JSON** with: summary, next_step, troubleshooting_suggestions (HTML list), system_actions (optional HTML list).

### Systems we use
1. NinjaOne (RMM)
2. Microsoft 365 (tenant management)
3. CIPP (multi-tenant admin)

### Ticket
- ID: ${ticket_id}
- Subject: ${subject}
- Details:
${details}
`;
return [{ json: { prompt, ticket_id } }];

const raw = $json.output ?? '';
let clean = raw.trim();
if (clean.startsWith('```')) {
  clean = clean.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/,'').trim();
}
let parsed; try { parsed = JSON.parse(clean); } catch (e) { throw new Error('Failed to parse LLM JSON: ' + e.message); }
return [{ json: { summary: parsed.summary, next_step: parsed.next_step, troubleshooting: parsed.troubleshooting_suggestions, ticket_id: $json.ticket_id } }];

const ticket_id = $items('Extract Ticket', 0, 0)[0]?.json?.ticket_id; if (!ticket_id) throw new Error('ticket_id missing');
const summary = String($json.summary||'').trim();
const next_step = String($json.next_step||'').trim();
const troubleshooting_html = String($json.troubleshooting||'').trim();
const LOGO_URL = 'https://YOUR_LOGO_URL/logo.png'; // <- change
const BRAND = 'Your MSP Brand';
const note_html = `
<div style="font-family: Arial, sans-serif; font-size: 14px; color: #333; background: #fafafa; padding: 16px; border-radius: 8px; border: 1px solid #ddd; line-height: 1.6;">
  <div style="text-align: center; margin-bottom: 20px;"><img src="${LOGO_URL}" alt="${BRAND}" style="max-width: 180px; height: auto;" /></div>
  <h2 style="color: #0055a5; margin-top: 0; border-bottom: 1px solid #ccc; padding-bottom: 6px;">🧠 AI Ticket Summary</h2>
  <p><strong>Ticket ID:</strong> ${ticket_id}</p>
  <h3 style="margin-top: 24px;">Summary</h3><div>${summary || 'n/a'}</div>
  <h3 style="margin-top: 24px;">Next Step</h3><div>${next_step || 'n/a'}</div>
  <h3 style="margin-top: 24px;">Troubleshooting Suggestions</h3><div>${troubleshooting_html || '<em>None</em>'}</div>
  <hr style="margin: 30px 0; border: none; border-top: 1px solid #ccc;" />
  <p style="font-size: 12px; color: #666;">This note was generated automatically by <strong>${BRAND} – AI Assistant</strong>.</p>
</div>`;
return [{ json: { ticket_id, note_html } }];
